      out.push({
        kind: 'spot_elevation',
        id: el.id,
        positionMm: el.positionMm,
        elevationMm: el.elevationMm,
        prefix: el.prefix ?? '',
        suffix: el.suffix ?? '',
        colour: el.colour ?? '#202020',
      });
    } else if (el.kind === 'revision_cloud' && el.hostViewId === viewId) {
      out.push({
